#include <bits/stdc++.h>
using namespace std;
struct Node{
    int end,sum;
};
int n,m,v[200005];
priority_queue<Node> pq[200005];
bool operator<(Node const x,Node const y){
    return x.end>y.end;
}
int main(){
    cin>>n>>m;
    for(int i=1;i<=n;i++)
        cin>>v[i];
    while(m--){
        int a,b,c,d;
        cin>>a>>b>>c>>d;
        while(pq[b].size() && pq[b].top().end<=a)
            v[b]+=pq[b].top().sum,pq[b].pop();
        if(v[b]<d)
            cout<<"-1\n";
        else{
            v[b]-=d;
            Node t={a+c,d};
            pq[b].push(t);
            cout<<v[b]<<'\n';
        }
    }
    return 0;
}
